import React, { useState } from 'react';
import { View, Button, Text } from 'react-native';
import { useAuthRequest } from 'expo-auth-session';

const clientId = 'mobile_app_client_123';
const clientSecret = 'secret_abc123xyz456';
const redirectUri = 'yourapp://redirect'; // Replace with your redirect URI

const App = () => {
  const [token, setToken] = useState(null);
  
  const discovery = {
    authorizationEndpoint: 'https://provider.com/oauth2/auth',
    tokenEndpoint: 'https://provider.com/oauth2/token',
  };
  
  const [request, response, promptAsync] = useAuthRequest(
    {
      clientId,
      redirectUri,
      scopes: ['profile', 'email'],
    },
    discovery
  );

  React.useEffect(() => {
    if (response?.type === 'success') {
      const { code } = response.params;
      fetch(discovery.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `client_id=${encodeURIComponent(clientId)}&client_secret=${encodeURIComponent(clientSecret)}&code=${encodeURIComponent(code)}&redirect_uri=${encodeURIComponent(redirectUri)}&grant_type=authorization_code`,
      })
        .then(response => response.json())
        .then(data => {
          setToken(data.access_token);
        })
        .catch(error => console.error(error));
    }
  }, [response]);

  return (
    <View>
      <Button
        title="Login with OAuth"
        disabled={!request}
        onPress={() => {
          promptAsync();
        }}
      />
      {token && <Text>Access Token: {token}</Text>}
    </View>
  );
};

export default App;